class Solution(object):
    def maxBalancedSubsequenceSum(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        # Transform: nums[i] - nums[j] >= i - j becomes nums[i] - i >= nums[j] - j
        # So we need max(nums[x] - x + nums[j]) where j < i and nums[j] - j <= nums[i] - i

        # Use segment tree with coordinate compression
        transformed = [(nums[i] - i, nums[i], i) for i in range(len(nums))]

        # Get all unique (nums[i] - i) values for coordinate compression
        coords = sorted(set(t[0] for t in transformed))
        coord_map = {v: i for i, v in enumerate(coords)}

        # Segment tree for range max query
        class SegmentTree:
            def __init__(self, size):
                self.size = size
                self.tree = [float('-inf')] * (4 * size)

            def update(self, idx, val, node=0, l=0, r=None):
                if r is None:
                    r = self.size - 1
                if l == r:
                    self.tree[node] = max(self.tree[node], val)
                    return
                mid = (l + r) // 2
                if idx <= mid:
                    self.update(idx, val, 2*node+1, l, mid)
                else:
                    self.update(idx, val, 2*node+2, mid+1, r)
                self.tree[node] = max(self.tree[2*node+1], self.tree[2*node+2])

            def query(self, ql, qr, node=0, l=0, r=None):
                if r is None:
                    r = self.size - 1
                if ql > qr or ql > r or qr < l:
                    return float('-inf')
                if ql <= l and r <= qr:
                    return self.tree[node]
                mid = (l + r) // 2
                return max(self.query(ql, qr, 2*node+1, l, mid),
                          self.query(ql, qr, 2*node+2, mid+1, r))

        seg_tree = SegmentTree(len(coords))
        result = float('-inf')

        for trans_val, num, i in transformed:
            coord_idx = coord_map[trans_val]
            # Query max value for all coord_idx <= current
            max_prev = seg_tree.query(0, coord_idx)

            # Current contribution
            current_sum = num + max(0, max_prev)  # Can start fresh or extend
            result = max(result, current_sum)

            # Update for future queries
            seg_tree.update(coord_idx, current_sum)

        return result
